/**
 * Get lab data for a product
 * Supports direct slug match and partial matches
 */
export function getLabData(slug: string): ProductLabData | null {
    // Direct match
    if (labData[slug]) return labData[slug];

    // Partial match (e.g., slug contains 'anker-737')
    for (const key of Object.keys(labData)) {
        if (slug.includes(key) || key.includes(slug)) {
            return labData[key];
        }
    }

    return null;
}

/**
 * Get lab metrics for a product — numeric test measurements
 */
export function getLabMetrics(slug: string): LabMetrics | null {
    const data = getLabData(slug);
    return data?.labMetrics ?? null;
}
